def valid_space(board, position):
  if position[0] < 0 or position[0] >= BOARD_SIZE:
    return False
  elif position[1] < 0 or position[1] >= BOARD_SIZE:
    return False
  elif board[position[0], position[1]] != 0:
    return False
  else:
